import requests
import json

url = "https://api.hyperzod.app/store/v1/cart"

payload = json.dumps({
   "cart_id": "",
   "user_id": 0,
   "cart_items": [
      {}
   ]
})
headers = {
   'accept': 'application/json',
   'content-type': 'application/json',
   'x-api-key': '{{X-API-KEY}}',
   'x-tenant': '{{X-Tenant}}'
}

response = requests.request("POST", url, headers=headers, data=payload)

print(response.text)

